    for pkg in (CLIENTS_DIR / "packages").iterdir():
        name = pkg.name.replace("client-", "").replace("-kit", "")
        clients.append({
            "name": name,
            "path": str(pkg),
            "package": pkg.name,
        })
    return clients

def get_client_details(name: str) -> dict:
    """Get detailed info about a specific client."""
    details = {}
    # Search for JSON content files
    for f in CLIENTS_DIR.rglob("**/*"):
        if f.is_file() and f.suffix in (".json", ".md", ".ts", ".tsx"):
            rel = f.relative_to(CLIENTS_DIR)
            if name.lower() in str(rel).lower():
                parts = list(rel.parts)
                details.setdefault("files", []).append(str(rel))
    return details

def get_recent_work() -> list:
    """Get recent project work context."""
