{"content": """"
Multi-Agent MCP Server for Hermes Client Agents.
Exposes each client agent as discoverable tools for Joinly.
"""
import json, os, sys, subprocess
from pathlib import Path

AGENTS_DIR = Path("/root/ai-agents")

def get_all_agents():
    agents = {}
    for d in AGENTS_DIR.iterdir():
        profile = d / "profile.json"
        if profile.exists():
            data = json.loads(profile.read_text())
            agents[data["client_name"]] = {
                "repo": data["repo"],
                "client_info": data["client_info"][:100],
                "meetings": len(data.get("meeting_history", [])),
                "profile": str(profile),
                "prompt_path": str(d / "system-prompt.txt"),
            }
    return agents

def get_agent_context(name: str) -> str:
    """Get full context for a specific agent."""
    result = subprocess.run(
        ["python3", str(AGENTS_DIR / "create-agent.py"), "context", name],
        capture_output=True, text=True, timeout=10
    )
    return result.stdout

# === MCP Handler ===
line = sys.stdin.read()
if not line.strip():
    response = {"jsonrpc": "2.0", "id": 1, "result": {"tools": [
        {
            "name": "list_agents",
            "description": "List all client agents with their repos and meeting counts",
            "inputSchema": {"type": "object", "properties": {}}
        },
        {
            "name": "get_agent",
            "description": "Get full context about a specific client agent (repos, meetings, interview questions)",
            "inputSchema": {
                "type": "object",
                "properties": {
                    "name": {"type": "string", "description": "Agent/client name (e.g. nexa-paraguay)"}
                },
                "required": ["name"]
            }
        },
        {
            "name": "save_meeting",
            "description": "Save a meeting summary to a client agent's memory",
            "inputSchema": {
                "type": "object",
                "properties": {
                    "name": {"type": "string"},
                    "summary": {"type": "string"},
                    "transcript_path": {"type": "string"}
                },
                "required": ["name", "summary"]
            }
        },
    ]}}
    print(json.dumps(response))
    sys.exit(0)

request = json.loads(line)
method = request.get("method")
params = request.get("params", {})
req_id = request.get("id", 1)

result = {}

if method == "tools/list":
    result = {"tools": [
        {"name": "list_agents", "description": "List all client agents", "inputSchema": {"type": "object", "properties": {}}},
        {"name": "get_agent", "description": "Get full context about a client agent", "inputSchema": {"type": "object", "properties": {"name": {"type": "string"}}, "required": ["name"]}},
        {"name": "save_meeting", "description": "Save meeting summary to agent memory", "inputSchema": {"type": "object", "properties": {"name": {"type": "string"}, "summary": {"type": "string"}}, "required": ["name", "summary"]}},
    ]}
elif method == "tools/call":
    tool = params.get("name")
    args = params.get("arguments", {})

    if tool == "list_agents":
        agents = get_all_agents()
        text = "\n".join(f"{k}: {v['repo'].split('/')[-1]} ({v['meetings']} meetings)" for k,v in agents.items())
        result = {"content": [{"type": "text", "text": text or "No agents found"}]}
    elif tool == "get_agent":
        name = args.get("name", "")
        ctx = get_agent_context(name)
        result = {"content": [{"type": "text", "text": ctx or "Agent not found"}]}
    elif tool == "save_meeting":
        subprocess.run(["python3", str(AGENTS_DIR / "create-agent.py"), "meeting", args["name"], args["summary"]])
        result = {"content": [{"type": "text", "text": "Meeting saved"}]}

print(json.dumps({"jsonrpc": "2.0", "id": req_id, "result": result}))
", "path": "/root/ai-agents/agent-mcp-server.py"}

