"""Pre-fetch repo context for meeting bot.
Gives the bot actual code/file context before it joins the meeting.
"""
import json, subprocess, sys, tempfile
from pathlib import Path

def clone_or_pull_repo(repo_url: str) -> Path:
    """Clone or pull the repo to a temp directory."""
    repo_name = repo_url.rstrip("/").split("/")[-1]
    repo_path = Path("/tmp/repo-cache") / repo_name
    if repo_path.exists():
        subprocess.run(["git", "-C", str(repo_path), "pull", "-q"], capture_output=True)
    else:
        repo_path.parent.mkdir(parents=True, exist_ok=True)
        subprocess.run(["git", "clone", "-q", repo_url, str(repo_path)], capture_output=True)
    return repo_path

def extract_repo_context(repo_path: Path) -> str:
    """Extract key files from the repo to give the LLM context."""
    context = []
    context.append(f"# Repo: {repo_path.name}")

    # README
    readme_files = list(repo_path.glob("README*")) + list(repo_path.glob("readme*"))
    for rf in readme_files:
        try:
            text = rf.read_text()[:2000]
            context.append(f"\n## README\n{text}")
        except:
            pass

    # package.json / composer.json / requirements.txt
    for config_file in repo_path.glob("{package.json,composer.json,requirements.txt,pyproject.toml,*.config.*}"):
        try:
            text = config_file.read_text()[:1000]
            context.append(f"\n## {config_file.name}\n{text}")
        except:
            pass

    # Structure
    structure = subprocess.run(
        ["find", str(repo_path), "-maxdepth", "3", "-not", "-path", "*/node_modules/*", "-not", "-path", "*/.*", "-type", "f"],
        capture_output=True, text=True, timeout=10
    )
    lines = structure.stdout.strip().split("\n")
    if lines:
        context.append(f"\n## Structure ({len(lines)} files)\n")
        for line in lines[:30]:
            context.append(line.replace(str(repo_path)+"/", ""))

    return "\n".join(context)

if __name__ == "__main__":
    repo_url = sys.argv[1] if len(sys.argv) > 1 else ""
    if not repo_url:
        repo_url = "https://github.com/Ai-Whisperers/elviajero-comercio"

    print(f"Fetching repo context for: {repo_url}")
    path = clone_or_pull_repo(repo_url)
    context = extract_repo_context(path)
    print(context)
